const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { Client } = require('pg'); // PostgreSQL client

const sqsClient = new SQSClient({ region: "us-east-1" });
const queueUrl = "https://sqs.us-east-1.amazonaws.com/123456789012/YourQueueName";

const dbClient = new Client({
  user: 'dbuser',
  host: 'database.server.com',
  database: 'mydb',
  password: 'secretpassword',
  port: 5432,
});

async function processMessage(message) {
  try {
    const transaction = JSON.parse(message.Body);
    const query = 'UPDATE transactions SET status = $1 WHERE transaction_id = $2';
    const values = [transaction.status, transaction.transaction_id];

    await dbClient.query(query, values);
    console.log(`Processed transaction ${transaction.transaction_id}`);
  } catch (error) {
    console.error("Error processing message:", error);
  }
}

async function receiveMessages() {
  try {
    const command = new ReceiveMessageCommand({
      QueueUrl: queueUrl,
      MaxNumberOfMessages: 10,
      WaitTimeSeconds: 20,
    });

    const response = await sqsClient.send(command);
    if (response.Messages) {
      for (const message of response.Messages) {
        await processMessage(message);

        const deleteCommand = new DeleteMessageCommand({
          QueueUrl: queueUrl,
          ReceiptHandle: message.ReceiptHandle,
        });
        await sqsClient.send(deleteCommand);
      }
    }
  } catch (error) {
    console.error("Error receiving messages:", error);
  }
}

async function startConsumer() {
  await dbClient.connect();
  console.log("Connected to the database.");

  setInterval(receiveMessages, 1000);
}

startConsumer().catch(console.error);